```cpp
#include <reaction/core/observer_node.h>
#include <reaction/graph/observer_graph.h>
#include <memory>
#include <string>
#include <utility>

namespace test_reaction {

// Observer node implementation
class TestChainedObserver : public reaction::ObserverNode {
public:
    TestChainedObserver(const std::string& name) : m_name(name), m_changed(false) {}

    void valueChanged(bool changed = true) override {
        m_changed = changed;
        m_callCount++;
        // Propagate notification to observers
        ObserverNode::valueChanged(changed);
    }

    bool wasChanged() const { return m_changed; }
    int getCallCount() const { return m_callCount; }
    const std::string& getName() const { return m_name; }

    void reset() {
        m_changed = false;
        m_callCount = 0;
    }

private:
    std::string m_name;
    bool m_changed;
    int m_callCount = 0;
};

// Function implementation
std::pair<int, bool> test_chained_observers(const std::string& targetName, 
                                            const std::string& observer1Name, 
                                            const std::string& observer2Name) {
    // Reset call counts for all nodes
    auto& graph = reaction::ObserverGraph::getInstance();

    // Create observer nodes
    auto target = std::make_shared<TestChainedObserver>(targetName);
    auto observer1 = std::make_shared<TestChainedObserver>(observer1Name);
    auto observer2 = std::make_shared<TestChainedObserver>(observer2Name);

    // Register nodes with the graph
    graph.addNode(target);
    graph.addNode(observer1);
    graph.addNode(observer2);

    // Set up observer relationships: target -> observer1 -> observer2
    graph.addObserver(target, observer1);
    graph.addObserver(observer1, observer2);

    // Notify the target
    target->valueChanged(true);

    // Verify all observers were notified
    bool observer1Notified = observer1->wasChanged();
    bool observer2Notified = observer2->wasChanged();

    // Calculate total call count
    int totalCalls = target->getCallCount() + 
                    observer1->getCallCount() + 
                    observer2->getCallCount();

    // Chain is valid if both observers were notified and each node called itself once
    bool chainValid = (observer1Notified && observer2Notified) &&
                     (target->getCallCount() == 1) &&
                     (observer1->getCallCount() == 1) &&
                     (observer2->getCallCount() == 1);

    return {totalCalls, chainValid};
}

}  // namespace test_reaction
```

**Explanation:**

1. **Node Creation**: We create three observer nodes using `std::make_shared` for proper memory management.

2. **Graph Registration**: Each node is registered with the global `ObserverGraph` instance to participate in the notification system.

3. **Relationship Setup**: We establish a chain where `target` observes `observer1`, and `observer1` observes `observer2`.

4. **Notification**: When we call `valueChanged()` on the target, it triggers the chain reaction through all observers.

5. **Verification**: We check that:
   - Both observers received the change notification
   - Each node only called its own `valueChanged()` method once
   - The total call count matches our expectations

6. **Return Value**: The function returns a pair containing the total number of notifications sent and a boolean indicating whether the chained notification worked correctly.

This solution demonstrates proper use of the Reaction framework's observer pattern with chained notifications, ensuring that changes propagate correctly through the observer hierarchy.

