RollbackObservation test_observer_state_rollback() {
    auto& graph = reaction::ObserverGraph::getInstance();

    // Create nodes
    auto sensor1 = std::make_shared<RecordingNode>();
    auto sensor2 = std::make_shared<RecordingNode>();
    auto observer = std::make_shared<RecordingNode>();

    // Register nodes with graph
    graph.registerNode(sensor1);
    graph.registerNode(sensor2);
    graph.registerNode(observer);

    // Set up initial dependency: observer -> sensor1
    graph.bind(observer, sensor1);

    // Save initial state for rollback
    auto initialState = graph.saveStateForRollback();

    // Replace dependency transactionally: observer -> sensor2
    graph.beginTransaction();
    graph.unbind(observer, sensor1);
    graph.bind(observer, sensor2);
    graph.commitTransaction();

    // Trigger notification on sensor2
    sensor2->valueChanged();

    // Record notification count after second binding
    int notificationsAfterSecondBinding = observer->notificationCount();

    // Execute rollback to restore original dependency
    graph.rollbackToState(initialState);

    // Trigger notification on sensor1 (original dependency)
    sensor1->valueChanged();

    // Record notification count after rollback
    int notificationsAfterRollback = observer->notificationCount();

    return RollbackObservation{
        notificationsAfterSecondBinding,
        notificationsAfterRollback
    };
}

}  // namespace test_reaction
