    auto source1 = std::make_shared<reaction::ObserverNode>();
    auto source2 = std::make_shared<reaction::ObserverNode>();
    auto source3 = std::make_shared<reaction::ObserverNode>();

    auto& graph = reaction::ObserverGraph::getInstance();
    graph.registerNode(observer);
    graph.registerNode(source1);
    graph.registerNode(source2);
    graph.registerNode(source3);

    source1->attachObserver(observer);
    source1->notify(true);

    int initialCount = observer->notifications();

    source1->detachObserver(observer);
    source2->attachObserver(observer);

    source1->notify(true);
    int firstAfterUpdate = observer->notifications() - initialCount;

    source2->notify(true);
    int secondAfterUpdate = observer->notifications() - initialCount - firstAfterUpdate;

